import{_ as n,C as t,o as r,c as o,a2 as a,E as i}from"./chunks/framework.BKG_UbFK.js";const k=JSON.parse('{"title":"Permissions","description":"","frontmatter":{},"headers":[],"relativePath":"fr/features/permissions.md","filePath":"fr/features/permissions.md"}'),p={name:"fr/features/permissions.md"};function l(c,e,d,h,m,u){const s=t("Screenshot");return r(),o("div",null,[e[0]||(e[0]=a('<h1 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h1><p>Le panneau Permissions est une interface CRUD complète sur le modèle <code>Permission</code> de Spatie. Clearance n&#39;introduit jamais sa propre table de permissions - chaque permission que vous créez ici est une permission Spatie ordinaire, utilisable partout où l&#39;API de Spatie est utilisée (<code>$user-&gt;can()</code>, <code>Gate::allows()</code>, policies, <code>@can</code>).</p><h2 id="ce-que-fait-le-panneau" tabindex="-1">Ce que fait le panneau <a class="header-anchor" href="#ce-que-fait-le-panneau" aria-label="Permalink to &quot;Ce que fait le panneau&quot;">​</a></h2><ul><li><strong>Créer</strong> - ajouter une nouvelle permission, validée selon la <a href="#permission-naming-convention">convention de nommage</a> (sauf si désactivée) et limitée à une garde.</li><li><strong>Modifier</strong> - renommer une permission ou changer sa garde.</li><li><strong>Supprimer</strong> - retirer une permission et ses attributions de rôle/utilisateur (comportement de cascade Spatie standard).</li></ul>',4)),i(s,{src:"/screenshots/permissions-page.png",alt:"Panneau Permissions de Clearance listant les permissions groupées par préfixe de nommage",caption:"Le panneau Permissions liste chaque permission Spatie, groupée par préfixe de nommage."}),i(s,{src:"/screenshots/permission-form-modal.png",alt:"Formulaire de création/modification de permission avec validation de la convention de nommage",caption:"Le formulaire de permission valide la convention de nommage group-action avant l'enregistrement."}),e[1]||(e[1]=a(`<h2 id="convention-de-nommage-des-permissions" tabindex="-1">Convention de nommage des permissions <a class="header-anchor" href="#convention-de-nommage-des-permissions" aria-label="Permalink to &quot;Convention de nommage des permissions&quot;">​</a></h2><p>Les permissions doivent suivre le format <code>group-action</code> :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders-create       correct</span></span>
<span class="line"><span>orders-read         correct</span></span>
<span class="line"><span>store-orders-delete correct</span></span>
<span class="line"><span></span></span>
<span class="line"><span>create              wrong (bare action, no group)</span></span>
<span class="line"><span>orders.create       wrong (dot separator)</span></span>
<span class="line"><span>Orders-Create       wrong (camelCase)</span></span></code></pre></div><p>Le préfixe de groupe (<code>orders</code> dans <code>orders-create</code>) est ce que le <a href="/clearance-docs/fr/features/dashboard.html">Tableau de bord</a> utilise pour compter les groupes de permissions distincts.</p><div class="tip custom-block"><p class="custom-block-title">Désactiver le contrôle</p><p>Certaines équipes migrent depuis un schéma de nommage différent. Désactivez le contrôle par environnement :</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;enforce_naming_convention&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span></code></pre></div></div><h2 id="controle-d-acces" tabindex="-1">Contrôle d&#39;accès <a class="header-anchor" href="#controle-d-acces" aria-label="Permalink to &quot;Contrôle d&#39;accès&quot;">​</a></h2><p>L&#39;accès en lecture au panneau (visualiser la liste des permissions) nécessite <code>clearance-access</code>. Créer, modifier, ou supprimer une permission nécessite en plus <code>clearance-permissions-write</code> :</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-access&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$user</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">givePermissionTo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;clearance-permissions-write&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Les permissions <code>clearance-*</code> sont réservées</p><p>Les permissions <code>clearance-*</code> elles-mêmes (<code>clearance-access</code>, <code>clearance-permissions-write</code>, etc.) ne peuvent pas être créées, renommées, ou supprimées via ce panneau - même par un acteur <code>super_admin</code>. Elles sont gérées exclusivement par le propre flux d&#39;installation du package. Voir <a href="/clearance-docs/fr/features/super-admin.html#reserved-clearance-permissions">Super Admin</a>.</p></div><h2 id="route-et-composant-integre" tabindex="-1">Route et composant intégré <a class="header-anchor" href="#route-et-composant-integre" aria-label="Permalink to &quot;Route et composant intégré&quot;">​</a></h2><table tabindex="0"><thead><tr><th>URI</th><th>Nom de route</th><th>Description</th></tr></thead><tbody><tr><td><code>/clearance/permissions</code></td><td><code>clearance.permissions</code></td><td>CRUD des permissions avec validation du nommage par préfixe de groupe</td></tr></tbody></table><div class="language-blade vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">blade</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">livewire:clearance::permissions.permission-manager</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;</span></span></code></pre></div><h2 id="prochaines-etapes" tabindex="-1">Prochaines étapes <a class="header-anchor" href="#prochaines-etapes" aria-label="Permalink to &quot;Prochaines étapes&quot;">​</a></h2><ul><li><a href="/clearance-docs/fr/features/roles.html">Rôles</a> - assigner des permissions à un rôle, limitées à la garde.</li><li><a href="/clearance-docs/fr/features/super-admin.html">Super Admin</a> - le tableau complet des permissions d&#39;écriture fines.</li><li><a href="/clearance-docs/fr/guide/configuration.html">Référence de configuration</a> - <code>enforce_naming_convention</code>, <code>naming_separator</code>.</li></ul>`,14))])}const f=n(p,[["render",l]]);export{k as __pageData,f as default};
